with detail = 1 {
    with link = "line.nl.ARD" {
        let ar = path("d1.nl.ard");

        with railway = :first :double :cat:dc15 :pax {
            track(ar[:asl.yr, :haa.yu]);
            track(ar[:haa.yu, :lei.yh]);
            track(ar[:lei.yh, :lei.yw]);
            track(ar[:lei.yw, :dhs.yc]);
            track(ar[:dhs.yc, :sga.yh]);
            track(ar[:sga.yh, :rma]);
            track(ar[:rma, :rot.yu]);
            track(ar[:rot.yu, :rot]);
        }
    }
}

